def median_chain_value(spec: dict) -> float:
    """Median of the chain values, rounded to 2 places."""
    nums = spec["nums"]
    if not nums:
        return 0.0
    vals = sorted(nums)
    k = len(vals)
    mid = k // 2
    if k % 2 == 1:
        return round(float(vals[mid]), 2)
    return round((vals[mid - 1] + vals[mid]) / 2, 2)

