def positive_fraction(spec: dict) -> float:
    """Fraction of reachable nodes holding a positive value, rounded to 2 places."""
    adj = spec["adj"]; vals = spec["vals"]; start = spec["start"]
    seen = []
    queue = [start]
    while queue:
        n = queue.pop(0)
        if n in seen:
            continue
        seen.append(n)
        queue.extend(adj[n])
    pos = 0
    for n in seen:
        if vals[n] > 0:
            pos += 1
    return round(pos / len(seen), 2)

