def gates_passed(spec: dict) -> int:
    """Count toll gates passable in order with the starting budget."""
    wallet = spec["budget"]
    passed = 0
    for fee in spec["fees"]:
        if wallet < fee:
            break
        wallet -= fee
        passed += 1
    return passed

