def above_average_count(spec: dict) -> int:
    """Count reachable nodes strictly above the reachable average."""
    adj = spec["adj"]; vals = spec["vals"]; start = spec["start"]
    seen = []
    queue = [start]
    while queue:
        n = queue.pop(0)
        if n in seen:
            continue
        seen.append(n)
        queue.extend(adj[n])
    total = 0
    for n in seen:
        total += vals[n]
    avg = total / len(seen)
    count = 0
    for n in seen:
        if vals[n] > avg:
            count += 1
    return count

