def reach_from_max_child(spec: dict) -> int:
    """Count nodes reachable from the highest-valued direct child of start."""
    adj = spec["adj"]; vals = spec["vals"]
    kids = adj[spec["start"]]
    if not kids:
        return 0
    best = kids[0]
    for k in kids:
        if vals[k] > vals[best] or (vals[k] == vals[best] and k < best):
            best = k
    seen = []
    queue = [best]
    while queue:
        n = queue.pop(0)
        if n in seen:
            continue
        seen.append(n)
        queue.extend(adj[n])
    return len(seen)

