def far_probe_pair(spec: dict) -> list:
    """Find the farthest node from start, then count what it can reach."""
    adj = spec["adj"]; start = spec["start"]
    depth = {start: 0}
    queue = [start]
    while queue:
        n = queue.pop(0)
        for m in adj[n]:
            if m not in depth:
                depth[m] = depth[n] + 1
                queue.append(m)
    far = start
    for n in depth:
        if depth[n] > depth[far] or (depth[n] == depth[far] and n < far):
            far = n
    seen = []
    queue = [far]
    while queue:
        n = queue.pop(0)
        if n in seen:
            continue
        seen.append(n)
        queue.extend(adj[n])
    return [far, len(seen)]

